parameters.jsCode:
// Extract the Clean Name from Groq
const response = $input.item.json.choices[0].message.content;
const aiOutput = JSON.parse(response);

// Pass through all original data + the new Clean Name
return {
  ...($input.item.json),
  cleaned_name: aiOutput.cleaned_name
};

// 1. The Vault: Array of your 5 Groq API Keys
// REPLACE these placeholders with your actual keys from your 5 accounts
const keys = [ 
  "gsk_f7hD7yBOMzX",
  "gsk_apIg69NgwVVhs7DhH",
  "gsk_cJ4aBndeJe3",
  "gsk_kdEaT7r6o6pq5c"
];

// 2. The Spinner: Pick a random index from 0 to 4
const randomIndex = Math.floor(Math.random() * keys.length);
const selectedKey = keys[randomIndex];

// 3. Output: Pass the selected key + keep existing data
return {
  json: {
    ...$input.item.json, // Keep the Jina data/Lead data safe
    selected_key: selectedKey // The chosen key for this specific run
  }
};

