  .highlight-box {
    background: linear-gradient(135deg, #667eea15 0%, #764ba215 100%);
    border-left: 4px solid #667eea;
    padding: 28px 32px;
    margin: 32px 0;
    border-radius: 8px;
    box-shadow: 0 4px 12px rgba(102, 126, 234, 0.08);
  }

  .list-item {
    margin-bottom: 18px;
    font-size: 15.5px;
    line-height: 1.7;
    color: #2d3748;
    padding-left: 28px;
    position: relative;
  }

  .list-item:before {
    content: "";
    position: absolute;
    left: 0;
    top: 8px;
    width: 18px;
    height: 18px;
    background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
    border-radius: 50%;
    box-shadow: 0 2px 6px rgba(245, 87, 108, 0.3);
  }

  .list-item:last-child {
    margin-bottom: 0;
  }

