  .cta {
    font-size: 17px;
    font-weight: 700;
    color: #ffffff;
    margin: 32px 0 0 0;
    line-height: 1.6;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    padding: 20px 28px;
    border-radius: 8px;
    box-shadow: 0 6px 20px rgba(102, 126, 234, 0.25);
  }

