  .signature {
    margin-top: 45px;
    padding-top: 25px;
    border-top: 2px solid transparent;
    background: linear-gradient(white, white) padding-box,
                linear-gradient(90deg, #f093fb 0%, #f5576c 50%, #4facfe 100%) border-box;
  }

