    font-size: 17px;
    font-weight: 700;
    background: linear-gradient(120deg, #667eea 0%, #764ba2 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    margin: 0 0 6px 0;
  }

  .signature-title {
    font-size: 14px;
    color: #718096;
    margin: 0;
    font-weight: 500;
  }

  /* Decorative Elements */
  .corner-accent {
    position: absolute;
    width: 100px;
    height: 100px;
    opacity: 0.06;
  }

  .corner-accent-tl {
    top: 0;
    left: 0;
    background: linear-gradient(135deg, #667eea 0%, transparent 100%);
    border-radius: 0 0 100% 0;
  }

  .corner-accent-br {
    bottom: 0;
    right: 0;
    background: linear-gradient(135deg, transparent 0%, #764ba2 100%);
    border-radius: 100% 0 0 0;
  }

