        <div class="signature">
          <p class="signature-name">Faith Leke-Akingboye</p>
          <p class="signature-title">AI-Native Operations Architect</p>
        </div>
      </div>
    </div>

    <!-- Footer Accent -->
    <div class="footer-accent"></div>

  </div>
</div>

